      /* (3564) bare_label_keyword ::= WAIT */ yytestcase(yyruleno==3564);
      /* (3565) bare_label_keyword ::= WHEN */ yytestcase(yyruleno==3565);
      /* (3566) bare_label_keyword ::= WHITESPACE_P */ yytestcase(yyruleno==3566);
      /* (3567) bare_label_keyword ::= WORK */ yytestcase(yyruleno==3567);
      /* (3568) bare_label_keyword ::= WRAPPER */ yytestcase(yyruleno==3568);
      /* (3569) bare_label_keyword ::= WRITE */ yytestcase(yyruleno==3569);
      /* (3570) bare_label_keyword ::= XML_P */ yytestcase(yyruleno==3570);
      /* (3571) bare_label_keyword ::= XMLATTRIBUTES */ yytestcase(yyruleno==3571);
      /* (3572) bare_label_keyword ::= XMLCONCAT */ yytestcase(yyruleno==3572);
      /* (3573) bare_label_keyword ::= XMLELEMENT */ yytestcase(yyruleno==3573);
      /* (3574) bare_label_keyword ::= XMLEXISTS */ yytestcase(yyruleno==3574);
      /* (3575) bare_label_keyword ::= XMLFOREST */ yytestcase(yyruleno==3575);
      /* (3576) bare_label_keyword ::= XMLNAMESPACES */ yytestcase(yyruleno==3576);
      /* (3577) bare_label_keyword ::= XMLPARSE */ yytestcase(yyruleno==3577);
      /* (3578) bare_label_keyword ::= XMLPI */ yytestcase(yyruleno==3578);
      /* (3579) bare_label_keyword ::= XMLROOT */ yytestcase(yyruleno==3579);
      /* (3580) bare_label_keyword ::= XMLSERIALIZE */ yytestcase(yyruleno==3580);
      /* (3581) bare_label_keyword ::= XMLTABLE */ yytestcase(yyruleno==3581);
      /* (3582) bare_label_keyword ::= YES_P */ yytestcase(yyruleno==3582);
      /* (3583) bare_label_keyword ::= ZONE */ yytestcase(yyruleno==3583);
        break;
